import{_ as e,c as o,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Registro de Alterações: Atualizações de Funcionalidades | OpenSkills","description":"Veja o histórico de versões do OpenSkills, conheça novas funcionalidades como o comando update, links simbólicos, repositórios privados, e importantes melhorias e correções de problemas como proteção contra travessia de caminhos.","frontmatter":{"title":"Registro de Alterações: Atualizações de Funcionalidades | OpenSkills","sidebarTitle":"Veja as Novidades","subtitle":"Registro de Alterações: Atualizações de Funcionalidades | OpenSkills","description":"Veja o histórico de versões do OpenSkills, conheça novas funcionalidades como o comando update, links simbólicos, repositórios privados, e importantes melhorias e correções de problemas como proteção contra travessia de caminhos.","tags":["changelog","version history"],"order":1},"headers":[],"relativePath":"pt/numman-ali/openskills/changelog/changelog/index.md","filePath":"pt/numman-ali/openskills/changelog/changelog/index.md"}'),l={name:"pt/numman-ali/openskills/changelog/changelog/index.md"};function r(d,a,t,n,c,u){return i(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="registro-de-alteracoes" tabindex="-1">Registro de Alterações <a class="header-anchor" href="#registro-de-alteracoes" aria-label="Permalink to &quot;Registro de Alterações&quot;">​</a></h1><p>Esta página registra o histórico de versões do OpenSkills, ajudando você a entender as novas funcionalidades, melhorias e correções de problemas de cada versão.</p><hr><h2 id="_1-5-0-2026-01-17" tabindex="-1">[1.5.0] - 2026-01-17 <a class="header-anchor" href="#_1-5-0-2026-01-17" aria-label="Permalink to &quot;[1.5.0] - 2026-01-17&quot;">​</a></h2><h3 id="novas-funcionalidades" tabindex="-1">Novas Funcionalidades <a class="header-anchor" href="#novas-funcionalidades" aria-label="Permalink to &quot;Novas Funcionalidades&quot;">​</a></h3><ul><li><strong><code>openskills update</code></strong> - Atualiza habilidades instaladas das origens registradas (padrão: todas)</li><li><strong>Rastreamento de metadados de origem</strong> - Agora registra informações de origem durante a instalação para atualização confiável de habilidades</li></ul><h3 id="melhorias" tabindex="-1">Melhorias <a class="header-anchor" href="#melhorias" aria-label="Permalink to &quot;Melhorias&quot;">​</a></h3><ul><li><strong>Leitura de múltiplas habilidades</strong> - O comando <code>openskills read</code> agora suporta uma lista de nomes de habilidades separada por vírgulas</li><li><strong>Geração de instruções de uso</strong> - Otimizou as instruções de chamada do comando read em ambiente shell</li><li><strong>README</strong> - Adicionou guia de atualização e instruções de uso manual</li></ul><h3 id="correcoes-de-problemas" tabindex="-1">Correções de Problemas <a class="header-anchor" href="#correcoes-de-problemas" aria-label="Permalink to &quot;Correções de Problemas&quot;">​</a></h3><ul><li><strong>Otimização da experiência de atualização</strong> - Pula habilidades sem metadados de origem e lista essas habilidades sugerindo reinstalação</li></ul><hr><h2 id="_1-4-0-2026-01-17" tabindex="-1">[1.4.0] - 2026-01-17 <a class="header-anchor" href="#_1-4-0-2026-01-17" aria-label="Permalink to &quot;[1.4.0] - 2026-01-17&quot;">​</a></h2><h3 id="melhorias-1" tabindex="-1">Melhorias <a class="header-anchor" href="#melhorias-1" aria-label="Permalink to &quot;Melhorias&quot;">​</a></h3><ul><li><strong>README</strong> - Esclareceu o método de instalação local padrão do projeto, removeu sugestões redundantes de sync</li><li><strong>Mensagem de instalação</strong> - O instalador agora distingue claramente a instalação local padrão do projeto da opção <code>--global</code></li></ul><hr><h2 id="_1-3-2-2026-01-17" tabindex="-1">[1.3.2] - 2026-01-17 <a class="header-anchor" href="#_1-3-2-2026-01-17" aria-label="Permalink to &quot;[1.3.2] - 2026-01-17&quot;">​</a></h2><h3 id="melhorias-2" tabindex="-1">Melhorias <a class="header-anchor" href="#melhorias-2" aria-label="Permalink to &quot;Melhorias&quot;">​</a></h3><ul><li><strong>Documentação e diretrizes AGENTS.md</strong> - Todos os exemplos de comandos e instruções de uso geradas usam <code>npx openskills</code></li></ul><hr><h2 id="_1-3-1-2026-01-17" tabindex="-1">[1.3.1] - 2026-01-17 <a class="header-anchor" href="#_1-3-1-2026-01-17" aria-label="Permalink to &quot;[1.3.1] - 2026-01-17&quot;">​</a></h2><h3 id="correcoes-de-problemas-1" tabindex="-1">Correções de Problemas <a class="header-anchor" href="#correcoes-de-problemas-1" aria-label="Permalink to &quot;Correções de Problemas&quot;">​</a></h3><ul><li><strong>Instalação Windows</strong> - Corrigiu problema de verificação de caminho no sistema Windows (&quot;Security error: Installation path outside target directory&quot;)</li><li><strong>Versão CLI</strong> - <code>npx openskills --version</code> agora lê corretamente o número de versão do package.json</li><li><strong>SKILL.md no diretório raiz</strong> - Corrigiu problema de instalação de repositórios de habilidade única com SKILL.md no diretório raiz</li></ul><hr><h2 id="_1-3-0-2025-12-14" tabindex="-1">[1.3.0] - 2025-12-14 <a class="header-anchor" href="#_1-3-0-2025-12-14" aria-label="Permalink to &quot;[1.3.0] - 2025-12-14&quot;">​</a></h2><h3 id="novas-funcionalidades-1" tabindex="-1">Novas Funcionalidades <a class="header-anchor" href="#novas-funcionalidades-1" aria-label="Permalink to &quot;Novas Funcionalidades&quot;">​</a></h3><ul><li><p><strong>Suporte a links simbólicos</strong> - Habilidades agora podem ser instaladas por meio de links simbólicos no diretório de habilidades (<a href="https://github.com/numman-ali/openskills/issues/3" target="_blank" rel="noreferrer">#3</a>)</p><ul><li>Suporta atualizações baseadas em git criando links simbólicos a partir de repositórios clonados</li><li>Suporta fluxo de trabalho de desenvolvimento local de habilidades</li><li>Links simbólicos corrompidos são pulados de forma elegante</li></ul></li><li><p><strong>Caminho de saída configurável</strong> - O comando sync adicionou a opção <code>--output</code> / <code>-o</code> (<a href="https://github.com/numman-ali/openskills/issues/5" target="_blank" rel="noreferrer">#5</a>)</p><ul><li>Pode sincronizar para qualquer arquivo <code>.md</code> (como <code>.ruler/AGENTS.md</code>)</li><li>Se o arquivo não existir, cria automaticamente o arquivo e adiciona título</li><li>Cria automaticamente diretórios aninhados se necessário</li></ul></li><li><p><strong>Instalação de caminho local</strong> - Suporta instalação de habilidades a partir de diretórios locais (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>Suporta caminhos absolutos (<code>/path/to/skill</code>)</li><li>Suporta caminhos relativos (<code>./skill</code>, <code>../skill</code>)</li><li>Suporta expansão de til (<code>~/my-skills/skill</code>)</li></ul></li><li><p><strong>Suporte a repositórios git privados</strong> - Suporta instalação de habilidades a partir de repositórios privados (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>URLs SSH (<code>git@github.com:org/private-skills.git</code>)</li><li>URLs HTTPS com autenticação</li><li>Usa automaticamente chaves SSH do sistema</li></ul></li><li><p><strong>Suíte de testes abrangente</strong> - 88 testes em 6 arquivos de teste</p><ul><li>Testes unitários para detecção de links simbólicos, análise YAML</li><li>Testes de integração para comandos install, sync</li><li>Testes de ponta a ponta para fluxo completo de CLI</li></ul></li></ul><h3 id="melhorias-3" tabindex="-1">Melhorias <a class="header-anchor" href="#melhorias-3" aria-label="Permalink to &quot;Melhorias&quot;">​</a></h3><ul><li><p><strong>O sinalizador <code>--yes</code> agora pula todas as solicitações</strong> - Modo totalmente não interativo, adequado para CI/CD (<a href="https://github.com/numman-ali/openskills/issues/6" target="_blank" rel="noreferrer">#6</a>)</p><ul><li>Não solicita ao sobrescrever habilidades existentes</li><li>Exibe mensagem <code>Sobrescrevendo: &lt;nome-da-habilidade&gt;</code> ao pular solicitações</li><li>Todos os comandos agora podem ser executados em ambiente headless</li></ul></li><li><p><strong>Reordenação de fluxo de trabalho CI</strong> - As etapas de construção agora são executadas antes dos testes</p><ul><li>Garante que <code>dist/cli.js</code> exista para testes de ponta a ponta</li></ul></li></ul><h3 id="seguranca" tabindex="-1">Segurança <a class="header-anchor" href="#seguranca" aria-label="Permalink to &quot;Segurança&quot;">​</a></h3><ul><li><strong>Proteção contra travessia de caminhos</strong> - Verifica se o caminho de instalação permanece dentro do diretório de destino</li><li><strong>Desreferenciamento de link simbólico</strong> - <code>cpSync</code> usa <code>dereference: true</code> para copiar com segurança o destino do link simbólico</li><li><strong>Regex YAML não guloso</strong> - Previne ataques potenciais de ReDoS na análise de frontmatter</li></ul><hr><h2 id="_1-2-1-2025-10-27" tabindex="-1">[1.2.1] - 2025-10-27 <a class="header-anchor" href="#_1-2-1-2025-10-27" aria-label="Permalink to &quot;[1.2.1] - 2025-10-27&quot;">​</a></h2><h3 id="correcoes-de-problemas-2" tabindex="-1">Correções de Problemas <a class="header-anchor" href="#correcoes-de-problemas-2" aria-label="Permalink to &quot;Correções de Problemas&quot;">​</a></h3><ul><li>Limpeza da documentação README - Removeu seções duplicadas e sinalizadores incorretos</li></ul><hr><h2 id="_1-2-0-2025-10-27" tabindex="-1">[1.2.0] - 2025-10-27 <a class="header-anchor" href="#_1-2-0-2025-10-27" aria-label="Permalink to &quot;[1.2.0] - 2025-10-27&quot;">​</a></h2><h3 id="novas-funcionalidades-2" tabindex="-1">Novas Funcionalidades <a class="header-anchor" href="#novas-funcionalidades-2" aria-label="Permalink to &quot;Novas Funcionalidades&quot;">​</a></h3><ul><li>Sinalizador <code>--universal</code>, instala habilidades em <code>.agent/skills/</code> em vez de <code>.claude/skills/</code><ul><li>Adequado para ambientes multiagente (Claude Code + Cursor/Windsurf/Aider)</li><li>Evita conflito com plugins de mercado nativos do Claude Code</li></ul></li></ul><h3 id="melhorias-4" tabindex="-1">Melhorias <a class="header-anchor" href="#melhorias-4" aria-label="Permalink to &quot;Melhorias&quot;">​</a></h3><ul><li>A instalação local do projeto agora é a opção padrão (anteriormente era instalação global)</li><li>As habilidades são instaladas em <code>./.claude/skills/</code> por padrão</li></ul><hr><h2 id="_1-1-0-2025-10-27" tabindex="-1">[1.1.0] - 2025-10-27 <a class="header-anchor" href="#_1-1-0-2025-10-27" aria-label="Permalink to &quot;[1.1.0] - 2025-10-27&quot;">​</a></h2><h3 id="novas-funcionalidades-3" tabindex="-1">Novas Funcionalidades <a class="header-anchor" href="#novas-funcionalidades-3" aria-label="Permalink to &quot;Novas Funcionalidades&quot;">​</a></h3><ul><li>README abrangente de página única com análise técnica aprofundada</li><li>Comparação lado a lado com Claude Code</li></ul><h3 id="correcoes-de-problemas-3" tabindex="-1">Correções de Problemas <a class="header-anchor" href="#correcoes-de-problemas-3" aria-label="Permalink to &quot;Correções de Problemas&quot;">​</a></h3><ul><li>O rótulo de localização agora exibe corretamente <code>project</code> ou <code>global</code> com base no local de instalação</li></ul><hr><h2 id="_1-0-0-2025-10-26" tabindex="-1">[1.0.0] - 2025-10-26 <a class="header-anchor" href="#_1-0-0-2025-10-26" aria-label="Permalink to &quot;[1.0.0] - 2025-10-26&quot;">​</a></h2><h3 id="novas-funcionalidades-4" tabindex="-1">Novas Funcionalidades <a class="header-anchor" href="#novas-funcionalidades-4" aria-label="Permalink to &quot;Novas Funcionalidades&quot;">​</a></h3><ul><li>Lançamento inicial</li><li><code>npx openskills install &lt;source&gt;</code> - Instala habilidades a partir de repositórios do GitHub</li><li><code>npx openskills sync</code> - Gera XML <code>&lt;available_skills&gt;</code> para AGENTS.md</li><li><code>npx openskills list</code> - Exibe habilidades instaladas</li><li><code>npx openskills read &lt;name&gt;</code> - Carrega conteúdo da habilidade para o agente</li><li><code>npx openskills manage</code> - Exclusão interativa de habilidades</li><li><code>npx openskills remove &lt;name&gt;</code> - Remove a habilidade especificada</li><li>Interface TUI interativa para todos os comandos</li><li>Suporta o formato SKILL.md do Anthropic</li><li>Divulgação progressiva (carregar habilidades sob demanda)</li><li>Suporte para recursos empacotados (references/, scripts/, assets/)</li></ul><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código Fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código fonte</strong></summary><blockquote><p>Tempo de atualização: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th></tr></thead><tbody><tr><td>Registro de alterações original</td><td><a href="https://github.com/numman-ali/openskills/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td></tr></tbody></table></details>',53)])])}const p=e(l,[["render",r]]);export{m as __pageData,p as default};
